class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        ListNode* dummy = new ListNode(0);
        dummy->next = head;
        ListNode* cur = dummy;
        unordered_map<int, ListNode*> mp;
        int sum = 0;
        while (cur != nullptr) {
            sum += cur->val;
            if (mp.find(sum) != mp.end()) {
                ListNode* prev = mp[sum];
                int tempSum = sum;
                while (prev->next != cur) {
                    tempSum -= prev->next->val;
                    mp.erase(tempSum);
                    prev = prev->next;
                }
                prev->next = cur->next;
            } else {
                mp[sum] = cur;
            }
            cur = cur->next;
        }
        return dummy->next;
    }
};
